// ── helpers ──────────────────────────────────────────────
function hl(hex){
  const r=parseInt(hex.slice(1,3),16),g=parseInt(hex.slice(3,5),16),b=parseInt(hex.slice(5,7),16);
  return `rgba(${r},${g},${b},0.12)`;
}
function fmtDate(ds){
  if(!ds) return "";
  const [y,m,d]=ds.split("-");
  return `${d}/${m}/${y.slice(2)}`;
}
function fmtTime(t){
  if(!t) return "";
  const [h,mn]=t.split(":");
  return mn==="00"?`${parseInt(h)}h`:`${parseInt(h)}h${mn}`;
}
function toDateStr(d){
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
}
function getDaysInMonth(y,m){ return new Date(y,m+1,0).getDate(); }
function getFirstDay(y,m)   { return new Date(y,m,1).getDay(); }
function getWeekStart(d){ const dt=new Date(d); dt.setDate(dt.getDate()-dt.getDay()); return dt; }

function wappLink(phone,name,title,date,time,tpl){
  const def="Boa tarde, {nome}.\n\nPassando para confirmar nosso compromisso:\n{titulo}\n{data} as {hora}\n\nQualquer duvida, estou a disposicao.\n\nMarcella Peixoto";
  const msg=(tpl||def).replace("{nome}",name||"").replace("{titulo}",title||"").replace("{data}",fmtDate(date)).replace("{hora}",fmtTime(time));
  return `https://wa.me/${phone.replace(/\D/g,"")}?text=${encodeURIComponent(msg)}`;
}
function emailLink(email,name,title,date,time,notes){
  const subj=encodeURIComponent(`Confirmação: ${title}`);
  const body=encodeURIComponent(`Olá ${name},\n\nPassando para confirmar nosso compromisso:\n\n${title}\n${fmtDate(date)}${time?" as "+fmtTime(time):""}\n${notes?"\nObs: "+notes:""}\n\nAtenciosamente,\nMarcella Peixoto`);
  return `mailto:${email}?subject=${subj}&body=${body}`;
}
function calLink(title,date,time,endTime,notes){
  const pad=n=>String(n).padStart(2,"0");
  const toICS=(ds,ts)=>{
    const d=new Date(`${ds}T${ts||"00:00"}:00`);
    return `${d.getFullYear()}${pad(d.getMonth()+1)}${pad(d.getDate())}T${pad(d.getHours())}${pad(d.getMinutes())}00`;
  };
  const ics=["BEGIN:VCALENDAR","VERSION:2.0","BEGIN:VEVENT",
    `SUMMARY:${(title||"").replace(/,/g,"\\,")}`,
    `DTSTART:${toICS(date,time||"09:00")}`,
    `DTEND:${toICS(date,endTime||time||"10:00")}`,
    `DESCRIPTION:${(notes||"").replace(/,/g,"\\,")}`,
    "END:VEVENT","END:VCALENDAR"].join("\r\n");
  return "data:text/calendar;charset=utf8,"+encodeURIComponent(ics);
}

// ── localStorage ─────────────────────────────────────────
function load(key,fallback){
  try{ const v=localStorage.getItem(key); return v?JSON.parse(v):fallback; }catch{ return fallback; }
}
function save(key,val){ try{ localStorage.setItem(key,JSON.stringify(val)); }catch{} }

