export default function App(){
  const today=new Date();
  const todayStr=toDateStr(today);

  const [view,setView]   = useState("mensal");
  const [calY,setCalY]   = useState(today.getFullYear());
  const [calM,setCalM]   = useState(today.getMonth());
  const [wkStart,setWkStart] = useState(getWeekStart(today));
  const [selDay,setSelDay]   = useState(null);

  const [events,setEvents]     = useState(()=>load("mp_events",SAMPLE_EVENTS));
  const [goals,setGoals]       = useState(()=>load("mp_goals",SAMPLE_GOALS));
  const [tasks,setTasks]       = useState(()=>load("mp_tasks",SAMPLE_TASKS));
  const [cats,setCats]         = useState(()=>load("mp_cats",DEFAULT_CATS));
  const [clients,setClients]       = useState(()=>load("mp_clients",[]));
  const [showCliModal,setShowCliModal] = useState(false);
  const [editCli,setEditCli]       = useState(null);
  const [newCli,setNewCli]         = useState({name:"",phone:"",email:"",notes:""});
  const [reminder,setReminder] = useState(null);

  const [showEv,setShowEv]   = useState(false);
  const [showGoal,setShowGoal] = useState(false);
  const [showTask,setShowTask] = useState(false);
  const [showCat,setShowCat]  = useState(false);
  const [editEv,setEditEv]    = useState(null);
  const [editCat,setEditCat]  = useState(null);

  const [ev,setEv]     = useState(BLANK_EVENT);
  const [newGoal,setNewGoal] = useState("");
  const [newTask,setNewTask] = useState({text:"",priority:"media"});
  const [newCat,setNewCat]   = useState({label:"",bg:PALETTE[0]});

  // auto-save
  useEffect(()=>save("mp_events",events),[events]);
  useEffect(()=>save("mp_goals",goals),[goals]);
  useEffect(()=>save("mp_tasks",tasks),[tasks]);
  useEffect(()=>save("mp_cats",cats),[cats]);
  useEffect(()=>save("mp_clients",clients),[clients]);
  function saveCli(){
    if(!newCli.name.trim()) return;
    if(editCli) setClients(clients.map(c=>c.id===editCli.id?{...newCli,id:editCli.id}:c));
    else setClients([...clients,{...newCli,id:Date.now()}]);
    setShowCliModal(false); setEditCli(null); setNewCli({name:"",phone:"",email:"",notes:""});
  }

  // reminder
  useEffect(()=>{
    const f=events.find(e=>{
      if(!e.reminder||!e.contacts?.[0]?.phone) return false;
      const diff=new Date(`${e.date}T${e.time||"09:00"}`)-new Date();
      return diff>0&&diff<24*3600*1000;
    });
    if(f) setReminder(f);
  },[events]);

  const catMap=Object.fromEntries(cats.map(c=>[c.id,c]));
  const dim=getDaysInMonth(calY,calM);
  const fd=getFirstDay(calY,calM);
  const wkDays=Array.from({length:7},(_,i)=>{const d=new Date(wkStart);d.setDate(d.getDate()+i);return d;});

  function prevM(){ if(calM===0){setCalY(y=>y-1);setCalM(11);}else setCalM(m=>m-1); setSelDay(null); }
  function nextM(){ if(calM===11){setCalY(y=>y+1);setCalM(0);}else setCalM(m=>m+1); setSelDay(null); }
  function prevW(){ const d=new Date(wkStart);d.setDate(d.getDate()-7);setWkStart(d); }
  function nextW(){ const d=new Date(wkStart);d.setDate(d.getDate()+7);setWkStart(d); }

  function evForDate(ds){ return events.filter(e=>e.date===ds); }

  function openNew(date="",time=""){
    setEditEv(null);
    setEv({...BLANK_EVENT,date:date||todayStr,time,type:cats[0]?.id||"reuniao"});
    setShowEv(true);
  }
  function openEdit(e){ setEv({...e}); setEditEv(e); setShowEv(true); }
  function delEv(id){ setEvents(events.filter(e=>e.id!==id)); }

  function saveEv(){
    if(!ev.title||!ev.date) return;
    if(editEv){
      setEvents(events.map(e=>e.id===editEv.id?{...ev,id:editEv.id}:e));
    } else {
      const base={...ev,id:Date.now()};
      const all=[base];
      if(ev.recurrence!=="none"){
        for(let i=1;i<=12;i++){
          const dt=new Date(ev.date+"T12:00:00");
          if(ev.recurrence==="weekly")   dt.setDate(dt.getDate()+7*i);
          if(ev.recurrence==="biweekly") dt.setDate(dt.getDate()+14*i);
          if(ev.recurrence==="monthly")  dt.setMonth(dt.getMonth()+i);
          all.push({...base,id:Date.now()+i,date:toDateStr(dt)});
        }
      }
      setEvents(prev=>[...prev,...all]);
    }
    setShowEv(false); setEditEv(null); setEv(BLANK_EVENT);
  }

  function saveCat(){
    if(!newCat.label.trim()) return;
    if(editCat){ setCats(cats.map(c=>c.id===editCat.id?{...editCat,...newCat}:c)); }
    else{ setCats([...cats,{id:newCat.label.toLowerCase().replace(/\s+/g,"-")+"-"+Date.now(),...newCat}]); }
    setShowCat(false); setEditCat(null); setNewCat({label:"",bg:PALETTE[0]});
  }
  function delCat(id){
    const rem=cats.filter(c=>c.id!==id);
    setCats(rem);
    setEvents(events.map(e=>e.type===id?{...e,type:rem[0]?.id||""}:e));
  }

  const upcoming=[...events]
    .filter(e=>new Date(`${e.date}T${e.time||"00:00"}`)>=new Date())
    .sort((a,b)=>new Date(`${a.date}T${a.time||"00:00"}`)-new Date(`${b.date}T${b.time||"00:00"}`))
    .slice(0,5);
  const todayEvs=events.filter(e=>e.date===todayStr).sort((a,b)=>(a.time||"").localeCompare(b.time||""));

  // ── Event action buttons ──────────────────────────────
  const ActBtns=({e,compact=false})=>(
    <div style={{display:"flex",flexWrap:"wrap",gap:5,marginTop:compact?0:8}}>
      {e.contacts?.filter(c=>c.phone).map((c,i)=>(
        <a key={"w"+i} href={wappLink(c.phone,c.name,e.title,e.date,e.time,e.wappTemplate)}
          target="_blank" rel="noopener noreferrer" className="wbtn">
          WhatsApp{e.contacts.filter(c=>c.phone).length>1?(` ${c.name||i+1}`):""}
        </a>
      ))}
      {e.contacts?.filter(c=>c.email).map((c,i)=>(
        <a key={"e"+i} href={emailLink(c.email,c.name,e.title,e.date,e.time,e.notes)}
          className="ebtn">
          Email{e.contacts.filter(c=>c.email).length>1?(` ${c.name||i+1}`):""}
        </a>
      ))}
      {!compact&&e.date&&(
        <a href={calLink(e.title,e.date,e.time,e.endTime,e.notes)}
          download={`${e.title||"evento"}.ics`} className="cbtn">
          + Calendário iPhone
        </a>
      )}
    </div>
  );

  // ── Event card ────────────────────────────────────────
  const EvCard=({e})=>{
    const accent=catMap[e.type]?.bg||BRAND;
    return(
      <div style={{padding:"10px 12px",borderRadius:9,marginBottom:7,background:hl(accent),display:"flex",gap:9,transition:"transform .15s"}}
        onMouseEnter={x=>{x.currentTarget.style.transform="translateX(2px)";}}
        onMouseLeave={x=>{x.currentTarget.style.transform="none";}}>
        <div style={{width:3,borderRadius:2,background:accent,flexShrink:0,alignSelf:"stretch"}}/>
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",justifyContent:"space-between",gap:8}}>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:13,fontWeight:500,lineHeight:1.35}}>{e.title}</div>
              <div style={{fontSize:11,color:"#9A8878",marginTop:2}}>
                {e.allDay?"Dia inteiro":e.time?(`${fmtTime(e.time)}${e.endTime?" → "+fmtTime(e.endTime):""}`):""}
                {e.contacts?.[0]?.name&&` · ${e.contacts.map(c=>c.name).filter(Boolean).join(", ")}`}
              </div>
              {e.notes&&<div style={{fontSize:11,color:"#9A8878",marginTop:3,fontStyle:"italic"}}>{e.notes}</div>}
            </div>
            <div style={{display:"flex",gap:4,flexShrink:0}}>
              <button className="nb" onClick={()=>openEdit(e)} style={{fontSize:13,color:"#9A8878"}}>✏️</button>
              <button className="nb" onClick={()=>delEv(e.id)} style={{fontSize:13,color:"#9E4A4A"}}>🗑</button>
            </div>
          </div>
          <ActBtns e={e}/>
        </div>
      </div>
    );
  };

  // ── MODAL EVENTO ─────────────────────────────────────
  const EvModal=()=>(
    <div className="overlay" onClick={()=>setShowEv(false)}>
      <div className="modal" onClick={x=>x.stopPropagation()}>
        <div style={{fontSize:18,fontWeight:500,marginBottom:20}}>{editEv?"Editar Evento":"Novo Evento"}</div>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>

          <div><label className="lbl">Título</label>
            <input className="fi" value={ev.title} onChange={x=>setEv({...ev,title:x.target.value})} placeholder="Ex: Reunião com cliente"/>
          </div>

          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div className={`chk${ev.allDay?" done":""}`} onClick={()=>setEv({...ev,allDay:!ev.allDay})}>
              {ev.allDay&&<span style={{color:"white",fontSize:9}}>✓</span>}
            </div>
            <span style={{fontSize:12,color:"#9A8878"}}>Dia inteiro</span>
          </div>

          <div style={{display:"grid",gridTemplateColumns:ev.allDay?"1fr":"1fr 1fr 1fr",gap:10}}>
            <div style={{gridColumn:ev.allDay?"1/1":"1/4"}}>
              <label className="lbl">Data</label>
              <input className="fi" type="date" value={ev.date} onChange={x=>setEv({...ev,date:x.target.value})}/>
            </div>
            {!ev.allDay&&<>
              <div><label className="lbl">Início</label>
                <input className="fi" type="time" value={ev.time} onChange={x=>setEv({...ev,time:x.target.value})}/>
              </div>
              <div><label className="lbl">Fim</label>
                <input className="fi" type="time" value={ev.endTime} onChange={x=>setEv({...ev,endTime:x.target.value})}/>
              </div>
            </>}
          </div>

          <div><label className="lbl">Categoria</label>
            <select className="sel" value={ev.type} onChange={x=>setEv({...ev,type:x.target.value})}>
              {cats.map(c=><option key={c.id} value={c.id}>{c.label}</option>)}
            </select>
          </div>

          <div><label className="lbl">Recorrência</label>
            <select className="sel" value={ev.recurrence} onChange={x=>setEv({...ev,recurrence:x.target.value})}>
              <option value="none">Sem recorrência</option>
              <option value="weekly">Semanal</option>
              <option value="biweekly">Quinzenal</option>
              <option value="monthly">Mensal</option>
            </select>
            {ev.recurrence!=="none"&&<div style={{fontSize:10,color:"#9A8878",marginTop:4}}>Cria automaticamente os próximos 12 eventos</div>}
          </div>

          <div>
            <label className="lbl">Contatos</label>
            {clients.length>0&&(
              <select className="sel" style={{fontSize:12,marginBottom:8}} defaultValue=""
                onChange={x=>{const cli=clients.find(cl=>cl.id===+x.target.value);if(!cli)return;const cs=[...ev.contacts];cs[0]={name:cli.name,phone:cli.phone,email:cli.email};setEv({...ev,contacts:cs});}}>
                <option value="">Selecionar do cadastro de clientes...</option>
                {clients.map(cl=><option key={cl.id} value={cl.id}>{cl.name}</option>)}
              </select>
            )}
            {ev.contacts.map((c,i)=>(
              <div key={i} style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr auto",gap:7,marginBottom:8,alignItems:"center"}}>
                <input className="fi" value={c.name}  onChange={x=>{const cs=[...ev.contacts];cs[i]={...cs[i],name:x.target.value};setEv({...ev,contacts:cs});}} placeholder="Nome"/>
                <input className="fi" value={c.phone} onChange={x=>{const cs=[...ev.contacts];cs[i]={...cs[i],phone:x.target.value};setEv({...ev,contacts:cs});}} placeholder="WhatsApp"/>
                <input className="fi" value={c.email} onChange={x=>{const cs=[...ev.contacts];cs[i]={...cs[i],email:x.target.value};setEv({...ev,contacts:cs});}} placeholder="Email"/>
                {i>0
                  ?<button className="nb" onClick={()=>setEv({...ev,contacts:ev.contacts.filter((_,j)=>j!==i)})} style={{color:"#9E4A4A",fontSize:18,padding:"0 4px"}}>×</button>
                  :<div/>}
              </div>
            ))}
            <button className="bg" style={{color:BRAND,fontSize:11}} onClick={()=>setEv({...ev,contacts:[...ev.contacts,{name:"",phone:"",email:""}]})}>+ Adicionar contato</button>
          </div>

          <div>
            <label className="lbl">Mensagem WhatsApp personalizada</label>
            <textarea className="fi" value={ev.wappTemplate} onChange={x=>setEv({...ev,wappTemplate:x.target.value})}
              placeholder={"Use {nome}, {titulo}, {data}, {hora}\nEx: Boa tarde, {nome}. Confirmando {titulo} em {data} as {hora}.\n\nMarcella Peixoto"}
              style={{minHeight:72,fontSize:12}}/>
            <div style={{fontSize:9,color:"#B8A898",marginTop:3}}>Variáveis: {"{nome}"} {"{titulo}"} {"{data}"} {"{hora}"} — Data: 11/05/26 · Hora: 9h ou 14h30</div>
          </div>

          <div><label className="lbl">Notas</label>
            <textarea className="fi" value={ev.notes} onChange={x=>setEv({...ev,notes:x.target.value})} placeholder="Observações..."/>
          </div>

          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div className={`chk${ev.reminder?" done":""}`} onClick={()=>setEv({...ev,reminder:!ev.reminder})}>
              {ev.reminder&&<span style={{color:"white",fontSize:9}}>✓</span>}
            </div>
            <span style={{fontSize:12}}>Ativar lembrete</span>
          </div>
        </div>
        <div style={{display:"flex",gap:10,marginTop:20}}>
          <button className="bp" style={{flex:1}} onClick={saveEv}>Salvar</button>
          <button className="bo" onClick={()=>{setShowEv(false);setEditEv(null);}}>Cancelar</button>
        </div>
      </div>
    </div>
  );

  // ── MENSAL ───────────────────────────────────────────
  const Mensal=()=>(
    <div style={{maxWidth:1100,margin:"0 auto",padding:"24px"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <button className="nb" onClick={prevM} style={{border:"1px solid #E0D5C5",borderRadius:7,width:30,height:30,fontSize:16,color:BRAND,display:"flex",alignItems:"center",justifyContent:"center"}}>‹</button>
          <div style={{fontSize:20,fontWeight:500}}>{MONTHS[calM]} <span style={{color:BRAND,fontWeight:400}}>{calY}</span></div>
          <button className="nb" onClick={nextM} style={{border:"1px solid #E0D5C5",borderRadius:7,width:30,height:30,fontSize:16,color:BRAND,display:"flex",alignItems:"center",justifyContent:"center"}}>›</button>
        </div>
        <button className="bg" onClick={()=>{setCalY(today.getFullYear());setCalM(today.getMonth());}}>Hoje</button>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 296px",gap:20}}>
        <div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3,marginBottom:4}}>
            {DAYS_SHORT.map(d=><div key={d} style={{textAlign:"center",fontSize:10,fontWeight:600,letterSpacing:".08em",textTransform:"uppercase",color:"#9A8878",padding:"5px 0"}}>{d}</div>)}
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
            {Array.from({length:fd}).map((_,i)=><div key={"e"+i}/>)}
            {Array.from({length:dim}).map((_,i)=>{
              const d=i+1;
              const ds=`${calY}-${String(calM+1).padStart(2,"0")}-${String(d).padStart(2,"0")}`;
              const de=evForDate(ds);
              const isT=ds===todayStr, isSel=selDay===d;
              return(
                <div key={d} className={`cal-day${isSel?" sel":isT?" tod":""}`} onClick={()=>setSelDay(isSel?null:d)}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                    <span style={{fontSize:12,fontWeight:isT?600:400,color:isT?BRAND:"#2C1A0E",width:21,height:21,display:"flex",alignItems:"center",justifyContent:"center",borderRadius:"50%",background:isT?BRAND_LIGHT:"transparent"}}>{d}</span>
                    {de.length>0&&<span style={{fontSize:9,color:"#9A8878",fontWeight:500}}>{de.length}</span>}
                  </div>
                  <div style={{display:"flex",flexDirection:"column",gap:2}}>
                    {de.slice(0,2).map(e=>{
                      const acc=catMap[e.type]?.bg||BRAND;
                      return(<div key={e.id} style={{fontSize:10,fontWeight:500,padding:"1px 5px",borderRadius:3,background:hl(acc),color:acc,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",borderLeft:`2px solid ${acc}`}}>
                        {e.allDay?"":e.time&&<span style={{opacity:.7,marginRight:3}}>{fmtTime(e.time)}</span>}{e.title}
                      </div>);
                    })}
                    {de.length>2&&<div style={{fontSize:9,color:"#9A8878",paddingLeft:5}}>+{de.length-2} mais</div>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:14}}>
          <div className="card" style={{minHeight:100}}>
            {selDay?(()=>{
              const ds=`${calY}-${String(calM+1).padStart(2,"0")}-${String(selDay).padStart(2,"0")}`;
              const de=evForDate(ds).sort((a,b)=>(a.time||"").localeCompare(b.time||""));
              return(<>
                <div className="sec" style={{marginBottom:10}}>{String(selDay).padStart(2,"0")} de {MONTHS[calM]}</div>
                {de.length===0?<div style={{fontSize:12,color:"#B8A898",textAlign:"center",padding:"14px 0"}}>Nenhum evento</div>:de.map(e=><EvCard key={e.id} e={e}/>)}
                <button className="bo" style={{width:"100%",marginTop:10}} onClick={()=>openNew(ds)}>+ Adicionar neste dia</button>
              </>);
            })():(
              <div style={{display:"flex",alignItems:"center",justifyContent:"center",height:80}}>
                <div style={{fontSize:12,color:"#B8A898"}}>Selecione um dia</div>
              </div>
            )}
          </div>
          <div className="card">
            <div className="sec">Próximos eventos</div>
            {upcoming.length===0&&<div style={{fontSize:12,color:"#B8A898"}}>Nenhum evento futuro</div>}
            {upcoming.map(e=>{
              const acc=catMap[e.type]?.bg||BRAND;
              return(<div key={e.id} style={{display:"flex",gap:9,alignItems:"flex-start",marginBottom:11}}>
                <div style={{background:acc,borderRadius:7,padding:"3px 6px",textAlign:"center",minWidth:34,flexShrink:0}}>
                  <div style={{fontSize:13,fontWeight:600,color:"white",lineHeight:1.2}}>{e.date.slice(8)}</div>
                  <div style={{fontSize:8,color:"rgba(255,255,255,.8)",textTransform:"uppercase"}}>{MONTHS[parseInt(e.date.slice(5,7))-1].slice(0,3)}</div>
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:12,fontWeight:500,lineHeight:1.3}}>{e.title}</div>
                  <div style={{fontSize:11,color:"#9A8878"}}>{e.allDay?"Dia inteiro":fmtTime(e.time)}{e.contacts?.[0]?.name&&` · ${e.contacts[0].name}`}</div>
                  <ActBtns e={e} compact/>
                </div>
              </div>);
            })}
          </div>
          <div className="card">
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <div className="sec" style={{marginBottom:0}}>Metas</div>
              <button className="bg" onClick={()=>setView("metas")}>ver todas →</button>
            </div>
            <div style={{background:"#EEE4DA",borderRadius:6,height:5,overflow:"hidden",marginBottom:10}}>
              <div style={{background:BRAND,height:"100%",borderRadius:6,width:`${goals.length?(goals.filter(g=>g.done).length/goals.length)*100:0}%`,transition:"width .4s"}}/>
            </div>
            {goals.slice(0,3).map(g=>(
              <div key={g.id} style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                <div className={`chk${g.done?" done":""}`} onClick={()=>setGoals(goals.map(x=>x.id===g.id?{...x,done:!x.done}:x))}>
                  {g.done&&<span style={{color:"white",fontSize:9}}>✓</span>}
                </div>
                <span style={{fontSize:12,textDecoration:g.done?"line-through":"none",color:g.done?"#B8A898":"#2C1A0E"}}>{g.text}</span>
              </div>
            ))}
            <div style={{fontSize:10,color:"#9A8878",marginTop:4}}>{goals.filter(g=>g.done).length}/{goals.length} concluídas</div>
          </div>
        </div>
      </div>
    </div>
  );

  // ── SEMANAL ──────────────────────────────────────────
  const Semanal=()=>{
    const we=new Date(wkStart); we.setDate(we.getDate()+6);
    const sm=wkStart.getMonth()===we.getMonth();
    const lbl=sm?`${wkStart.getDate()}–${we.getDate()} de ${MONTHS[wkStart.getMonth()]} ${wkStart.getFullYear()}`:`${wkStart.getDate()} ${MONTHS[wkStart.getMonth()].slice(0,3)} – ${we.getDate()} ${MONTHS[we.getMonth()].slice(0,3)} ${wkStart.getFullYear()}`;
    return(
      <div style={{maxWidth:1200,margin:"0 auto",padding:"24px"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <button className="nb" onClick={prevW} style={{border:"1px solid #E0D5C5",borderRadius:7,width:30,height:30,fontSize:16,color:BRAND,display:"flex",alignItems:"center",justifyContent:"center"}}>‹</button>
            <div style={{fontSize:18,fontWeight:500}}>{lbl}</div>
            <button className="nb" onClick={nextW} style={{border:"1px solid #E0D5C5",borderRadius:7,width:30,height:30,fontSize:16,color:BRAND,display:"flex",alignItems:"center",justifyContent:"center"}}>›</button>
          </div>
          <button className="bg" onClick={()=>setWkStart(getWeekStart(today))}>Hoje</button>
        </div>
        <div className="card" style={{padding:0,overflow:"hidden"}}>
          {/* All-day events row */}
          <div style={{display:"flex",borderBottom:"2px solid #F0E8E0"}}>
            <div style={{width:50,flexShrink:0,background:"#FAF5F0",borderRight:"1px solid #F0E8E0",display:"flex",alignItems:"center",justifyContent:"center"}}>
              <span style={{fontSize:8,color:"#C0AFA0",writingMode:"vertical-rl",textTransform:"uppercase",letterSpacing:".06em"}}>dia todo</span>
            </div>
            {wkDays.map((d,i)=>{
              const ds=toDateStr(d); const isT=ds===todayStr;
              const allDayEvs=evForDate(ds).filter(e=>e.allDay);
              const cnt=evForDate(ds).filter(e=>!e.allDay).length;
              return(<div key={i} className="week-col" style={{padding:"6px 4px",textAlign:"center",background:isT?"#FDF6F0":"white",cursor:"pointer",minHeight:48}} onClick={()=>openNew(ds)}>
                <div style={{fontSize:10,fontWeight:600,letterSpacing:".08em",textTransform:"uppercase",color:isT?BRAND:"#9A8878"}}>{DAYS_SHORT[d.getDay()]}</div>
                <div style={{fontSize:20,fontWeight:isT?600:300,color:isT?BRAND:"#2C1A0E",lineHeight:1.2,marginTop:1}}>{d.getDate()}</div>
                {cnt>0&&<div style={{fontSize:8,color:"#9A8878"}}>{cnt}ev</div>}
                {allDayEvs.map(e=>{
                  const acc=catMap[e.type]?.bg||BRAND;
                  return(<div key={e.id} onClick={x=>{x.stopPropagation();openEdit(e);}}
                    style={{fontSize:9,fontWeight:500,padding:"1px 4px",borderRadius:3,background:hl(acc),color:acc,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",borderLeft:`2px solid ${acc}`,marginTop:2,cursor:"pointer",textAlign:"left"}}>
                    ◆ {e.title}
                  </div>);
                })}
              </div>);
            })}
          </div>
          <div style={{overflowY:"auto",maxHeight:"58vh"}}>
            {HOURS.map(h=>(
              <div key={h} style={{display:"flex",borderBottom:"1px solid #F8F2EC"}}>
                <div style={{width:50,flexShrink:0,padding:"4px 8px",background:"#FAF5F0",display:"flex",alignItems:"flex-start",justifyContent:"flex-end",borderRight:"1px solid #F0E8E0"}}>
                  <span style={{fontSize:10,color:"#C0AFA0",fontWeight:500,paddingTop:4}}>{String(h).padStart(2,"0")}h</span>
                </div>
                {wkDays.map((d,di)=>{
                  const ds=toDateStr(d); const isT=ds===todayStr;
                  const se=evForDate(ds).filter(e=>!e.allDay&&e.time&&parseInt(e.time.split(":")[0])===h);
                  return(<div key={di} className="week-col hcell" style={{background:isT?"#FDFAF6":"white"}} onClick={()=>openNew(ds,`${String(h).padStart(2,"0")}:00`)}>
                    {se.map(e=>{
                      const acc=catMap[e.type]?.bg||BRAND;
                      return(<div key={e.id} className="wev" style={{background:hl(acc),borderLeft:`2.5px solid ${acc}`}} onClick={x=>{x.stopPropagation();openEdit(e);}}>
                        <div style={{fontSize:10,color:acc,fontWeight:600}}>{fmtTime(e.time)}{e.endTime&&` → ${fmtTime(e.endTime)}`}</div>
                        <div style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{e.title}</div>
                        {e.contacts?.[0]?.name&&<div style={{fontSize:9,color:"#9A8878",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{e.contacts[0].name}</div>}
                      </div>);
                    })}
                  </div>);
                })}
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  // ── LISTA ────────────────────────────────────────────
  const Lista=()=>(
    <div style={{maxWidth:780,margin:"0 auto",padding:"24px"}}>
      <div style={{marginBottom:20,display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:12}}>
        <div style={{fontSize:20,fontWeight:500}}>Todos os Eventos</div>
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {cats.map(c=><span key={c.id} style={{display:"inline-block",padding:"2px 9px",borderRadius:20,fontSize:10,fontWeight:500,background:hl(c.bg),color:c.bg,textTransform:"uppercase",letterSpacing:".05em"}}>{c.label}</span>)}
        </div>
      </div>
      {events.length===0&&<div style={{textAlign:"center",padding:"60px 0",fontSize:13,color:"#B8A898"}}>Nenhum evento</div>}
      {Object.entries(
        [...events].sort((a,b)=>a.date.localeCompare(b.date)).reduce((acc,e)=>{const k=e.date.slice(0,7);if(!acc[k])acc[k]=[];acc[k].push(e);return acc;},{})
      ).map(([month,evs])=>(
        <div key={month} style={{marginBottom:22}}>
          <div style={{fontSize:10,fontWeight:600,letterSpacing:".12em",textTransform:"uppercase",color:"#9A8878",marginBottom:10,borderBottom:"1px solid #F0E8E0",paddingBottom:7}}>
            {MONTHS[parseInt(month.slice(5))-1]} {month.slice(0,4)}
          </div>
          {evs.map(e=>{
            const acc=catMap[e.type]?.bg||BRAND;
            return(<div key={e.id} style={{marginBottom:8,padding:"12px 14px",borderRadius:10,background:hl(acc),display:"flex",gap:11}}>
              <div style={{width:4,borderRadius:2,background:acc,flexShrink:0,alignSelf:"stretch"}}/>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
                  <div>
                    <div style={{fontSize:14,fontWeight:500}}>{e.title}</div>
                    <div style={{fontSize:11,color:"#9A8878",marginTop:2}}>
                      {e.date.slice(8)}/{e.date.slice(5,7)}
                      {e.allDay?" · Dia inteiro":e.time&&` · ${fmtTime(e.time)}${e.endTime?" → "+fmtTime(e.endTime):""}`}
                      {e.contacts?.[0]?.name&&` · ${e.contacts.map(c=>c.name).filter(Boolean).join(", ")}`}
                    </div>
                    {e.notes&&<div style={{fontSize:11,color:"#9A8878",marginTop:3,fontStyle:"italic"}}>{e.notes}</div>}
                  </div>
                  <div style={{display:"flex",gap:7,alignItems:"center",flexShrink:0}}>
                    <button className="nb" onClick={()=>openEdit(e)} style={{fontSize:14,color:"#9A8878"}}>✏️</button>
                    <button className="nb" onClick={()=>delEv(e.id)} style={{fontSize:14,color:"#9E4A4A"}}>🗑</button>
                  </div>
                </div>
                <ActBtns e={e}/>
              </div>
            </div>);
          })}
        </div>
      ))}
    </div>
  );

  // ── METAS ────────────────────────────────────────────
  const Metas=()=>(
    <div style={{maxWidth:900,margin:"0 auto",padding:"24px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:20}}>
      <div className="card">
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
          <div style={{fontSize:18,fontWeight:500}}>Metas <span style={{color:BRAND,fontWeight:400}}>do Mês</span></div>
          <button className="bo" onClick={()=>setShowGoal(true)}>+ Meta</button>
        </div>
        <div style={{background:"#EEE4DA",borderRadius:6,height:5,overflow:"hidden",marginBottom:10}}>
          <div style={{background:BRAND,height:"100%",borderRadius:6,width:`${goals.length?(goals.filter(g=>g.done).length/goals.length)*100:0}%`,transition:"width .4s"}}/>
        </div>
        <div style={{fontSize:11,color:"#9A8878",marginBottom:14}}>{goals.filter(g=>g.done).length} de {goals.length} concluídas</div>
        {goals.map(g=>(
          <div key={g.id} className="task-row">
            <div className={`chk${g.done?" done":""}`} onClick={()=>setGoals(goals.map(x=>x.id===g.id?{...x,done:!x.done}:x))}>
              {g.done&&<span style={{color:"white",fontSize:9}}>✓</span>}
            </div>
            <span style={{fontSize:13,flex:1,textDecoration:g.done?"line-through":"none",color:g.done?"#B8A898":"#2C1A0E"}}>{g.text}</span>
            <button className="nb" onClick={()=>setGoals(goals.filter(x=>x.id!==g.id))} style={{fontSize:13,color:"#D0C0B0"}}>✕</button>
          </div>
        ))}
        {goals.length===0&&<div style={{fontSize:13,color:"#B8A898",textAlign:"center",padding:"16px 0"}}>Nenhuma meta ainda</div>}
      </div>
      <div className="card">
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
          <div style={{fontSize:18,fontWeight:500}}>Tarefas <span style={{color:"#5C7D8A",fontWeight:400}}>Pendentes</span></div>
          <button className="bo" onClick={()=>setShowTask(true)}>+ Tarefa</button>
        </div>
        {["alta","media","baixa"].map(p=>{
          const ft=tasks.filter(t=>t.priority===p);
          if(!ft.length) return null;
          return(<div key={p} style={{marginBottom:14}}>
            <div style={{fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:".08em",color:p==="alta"?"#9E4A4A":p==="media"?"#8B7355":"#6B8F71",marginBottom:6}}>
              {p==="alta"?"🔴 Alta":p==="media"?"🟡 Média":"🟢 Baixa"}
            </div>
            {ft.map(t=>(
              <div key={t.id} className="task-row">
                <div className={`chk${t.done?" done":""}`} style={{borderColor:p==="alta"?"#9E4A4A":p==="media"?"#8B7355":"#6B8F71"}}
                  onClick={()=>setTasks(tasks.map(x=>x.id===t.id?{...x,done:!x.done}:x))}>
                  {t.done&&<span style={{color:"white",fontSize:9}}>✓</span>}
                </div>
                <span style={{fontSize:13,flex:1,textDecoration:t.done?"line-through":"none",color:t.done?"#B8A898":"#2C1A0E"}}>{t.text}</span>
                <button className="nb" onClick={()=>setTasks(tasks.filter(x=>x.id!==t.id))} style={{fontSize:12,color:"#D0C0B0"}}>✕</button>
              </div>
            ))}
          </div>);
        })}
        {tasks.length===0&&<div style={{fontSize:13,color:"#B8A898",textAlign:"center",padding:"16px 0"}}>Nenhuma tarefa ✨</div>}
      </div>
    </div>
  );


  // ── CLIENTES ──
  const ClientesView=()=>(
    <div style={{maxWidth:580,margin:"0 auto",padding:"24px"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <div style={{fontSize:20,fontWeight:500,color:"#2C1A0E"}}>Clientes</div>
        <button className="btn-primary" onClick={()=>{setEditCli(null);setNewCli({name:"",phone:"",email:"",notes:""});setShowCliModal(true);}}>+ Novo</button>
      </div>
      <div className="card">
        {clients.length===0&&<div style={{fontSize:13,color:"#B8A898",textAlign:"center",padding:"20px 0"}}>Nenhum cliente cadastrado</div>}
        {clients.map(c=>(
          <div key={c.id} style={{display:"flex",alignItems:"flex-start",gap:10,padding:"11px 0",borderBottom:"1px solid #F0E8E0"}}>
            <div style={{width:36,height:36,borderRadius:"50%",background:"#F5EDE4",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
              <span style={{fontSize:15,fontWeight:600,color:BRAND}}>{c.name.charAt(0).toUpperCase()}</span>
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:13,fontWeight:500}}>{c.name}</div>
              {c.phone&&<div style={{fontSize:11,color:"#9A8878"}}>{c.phone}</div>}
              {c.email&&<div style={{fontSize:11,color:"#9A8878"}}>{c.email}</div>}
              {c.notes&&<div style={{fontSize:11,color:"#B8A898",fontStyle:"italic",marginTop:2}}>{c.notes}</div>}
              <div style={{display:"flex",gap:5,marginTop:5,flexWrap:"wrap"}}>
                {c.phone&&<a href={`https://wa.me/${c.phone.replace(/\D/g,"")}`} target="_blank" rel="noopener noreferrer" style={{display:"inline-flex",alignItems:"center",gap:4,background:"#25D366",color:"white",borderRadius:5,padding:"3px 8px",fontSize:10,fontWeight:500,textDecoration:"none"}}>WhatsApp</a>}
                {c.email&&<a href={`mailto:${c.email}`} style={{display:"inline-flex",alignItems:"center",gap:4,background:"#5C7D8A",color:"white",borderRadius:5,padding:"3px 8px",fontSize:10,fontWeight:500,textDecoration:"none"}}>Email</a>}
              </div>
            </div>
            <div style={{display:"flex",gap:4}}>
              <button onClick={()=>{setEditCli(c);setNewCli({name:c.name,phone:c.phone,email:c.email,notes:c.notes||""});setShowCliModal(true);}} style={{background:"none",border:"none",cursor:"pointer",fontSize:13,color:"#9A8878"}}>✏️</button>
              <button onClick={()=>setClients(clients.filter(x=>x.id!==c.id))} style={{background:"none",border:"none",cursor:"pointer",fontSize:13,color:"#9E4A4A"}}>🗑</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  // ── CATEGORIAS ───────────────────────────────────────
  const Categorias=()=>(
    <div style={{maxWidth:560,margin:"0 auto",padding:"24px"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <div style={{fontSize:20,fontWeight:500}}>Categorias</div>
        <button className="bp" onClick={()=>{setEditCat(null);setNewCat({label:"",bg:PALETTE[0]});setShowCat(true);}}>+ Nova</button>
      </div>
      <div className="card">
        {cats.map(c=>(
          <div key={c.id} className="cat-row">
            <div style={{width:13,height:13,borderRadius:"50%",background:c.bg,flexShrink:0}}/>
            <div style={{flex:1,fontSize:13,fontWeight:500}}>{c.label}</div>
            <div style={{fontSize:11,color:"#C0AFA0",marginRight:10}}>{events.filter(e=>e.type===c.id).length} eventos</div>
            <button className="nb" onClick={()=>{setEditCat(c);setNewCat({label:c.label,bg:c.bg});setShowCat(true);}} style={{fontSize:13,color:"#9A8878",marginRight:4}}>✏️</button>
            <button className="nb" onClick={()=>delCat(c.id)} style={{fontSize:13,color:"#9E4A4A"}}>🗑</button>
          </div>
        ))}
        {cats.length===0&&<div style={{fontSize:13,color:"#B8A898",textAlign:"center",padding:"20px 0"}}>Nenhuma categoria</div>}
      </div>
      <div style={{marginTop:10,fontSize:10,color:"#C0AFA0",textAlign:"center"}}>Ao excluir, os eventos são migrados para a primeira categoria disponível.</div>
    </div>
  );

  // ── RENDER ───────────────────────────────────────────
  return(
    <div style={{fontFamily:"'Inter',sans-serif",background:"#F5EEE6",minHeight:"100vh",color:"#2C1A0E"}}>
      <style>{CSS}</style>

      {/* Reminder banner */}
      {reminder&&(
        <div className="rbanner">
          <div style={{fontSize:9,fontWeight:600,letterSpacing:".12em",textTransform:"uppercase",color:BRAND_MID,marginBottom:5}}>🔔 Lembrete</div>
          <div style={{fontSize:13,fontWeight:500,marginBottom:4}}>{reminder.title}</div>
          <div style={{fontSize:11,color:"#9A8878",marginBottom:10}}>{fmtTime(reminder.time)} · {reminder.contacts?.[0]?.name}</div>
          <ActBtns e={reminder} compact/>
          <div style={{marginTop:8}}><button className="bg" style={{fontSize:9}} onClick={()=>setReminder(null)}>DISPENSAR</button></div>
        </div>
      )}

      {/* Header */}
      <div style={{background:"white",borderBottom:"1px solid #EDE0D4",padding:"0 24px",position:"sticky",top:0,zIndex:50,boxShadow:"0 1px 6px rgba(80,40,10,.05)"}}>
        <div style={{maxWidth:1200,margin:"0 auto",display:"flex",alignItems:"center",justifyContent:"space-between",gap:12}}>
          <div style={{padding:"13px 0",flexShrink:0}}>
            <img src={`data:image/png;base64,${LOGO_B64}`} alt="marcella peixoto"
              style={{height:24,display:"block",filter:"brightness(0) saturate(100%) invert(35%) sepia(40%) saturate(500%) hue-rotate(350deg) brightness(80%)"}}/>
            <div style={{fontSize:9,fontWeight:600,letterSpacing:".14em",textTransform:"uppercase",color:"#9A8878",marginTop:5}}>
              {DAYS_FULL[today.getDay()]}, {today.getDate()} de {MONTHS[today.getMonth()]}
            </div>
          </div>
          <nav style={{display:"flex"}}>
            {[["mensal","Mensal"],["semanal","Semanal"],["lista","Lista"],["metas","Metas & Tarefas"],["clientes","Clientes"],["categorias","Cat."]].map(([v,l])=>(
              <button key={v} className={`nav-btn${view===v?" active":""}`} onClick={()=>setView(v)}>{l}</button>
            ))}
          </nav>
          <button className="bp" style={{flexShrink:0}} onClick={()=>openNew()}>+ Novo Evento</button>
        </div>
      </div>

      <div className="content-wrap">
      {/* Views */}
      {view==="mensal"     &&<Mensal/>}
      {view==="semanal"    &&<Semanal/>}
      {view==="lista"      &&<Lista/>}
      {view==="metas"      &&<Metas/>}
      {view==="clientes"   &&<ClientesView/>}
      {view==="categorias" &&<Categorias/>}

      </div>
      {/* Modals */}
      {showEv&&<EvModal/>}

      {showGoal&&(
        <div className="overlay" onClick={()=>setShowGoal(false)}>
          <div className="modal" onClick={x=>x.stopPropagation()} style={{maxWidth:380}}>
            <div style={{fontSize:18,fontWeight:500,marginBottom:16}}>Nova Meta</div>
            <input className="fi" value={newGoal} onChange={x=>setNewGoal(x.target.value)} placeholder="Ex: Fechar 2 contratos em maio"
              onKeyDown={x=>{if(x.key==="Enter"&&newGoal){setGoals([...goals,{id:Date.now(),text:newGoal,done:false}]);setNewGoal("");setShowGoal(false);}}}/>
            <div style={{display:"flex",gap:10,marginTop:14}}>
              <button className="bp" style={{flex:1}} onClick={()=>{if(newGoal){setGoals([...goals,{id:Date.now(),text:newGoal,done:false}]);setNewGoal("");setShowGoal(false);}}}>Adicionar</button>
              <button className="bo" onClick={()=>setShowGoal(false)}>Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {showTask&&(
        <div className="overlay" onClick={()=>setShowTask(false)}>
          <div className="modal" onClick={x=>x.stopPropagation()} style={{maxWidth:380}}>
            <div style={{fontSize:18,fontWeight:500,marginBottom:16}}>Nova Tarefa</div>
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div><label className="lbl">Tarefa</label><input className="fi" value={newTask.text} onChange={x=>setNewTask({...newTask,text:x.target.value})} placeholder="Descreva a tarefa..."/></div>
              <div><label className="lbl">Prioridade</label>
                <select className="sel" value={newTask.priority} onChange={x=>setNewTask({...newTask,priority:x.target.value})}>
                  <option value="alta">🔴 Alta</option>
                  <option value="media">🟡 Média</option>
                  <option value="baixa">🟢 Baixa</option>
                </select>
              </div>
            </div>
            <div style={{display:"flex",gap:10,marginTop:14}}>
              <button className="bp" style={{flex:1}} onClick={()=>{if(newTask.text){setTasks([...tasks,{id:Date.now(),...newTask,done:false}]);setNewTask({text:"",priority:"media"});setShowTask(false);}}}>Adicionar</button>
              <button className="bo" onClick={()=>setShowTask(false)}>Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {showCat&&(
        <div className="overlay" onClick={()=>setShowCat(false)}>
          <div className="modal" onClick={x=>x.stopPropagation()} style={{maxWidth:400}}>
            <div style={{fontSize:18,fontWeight:500,marginBottom:20}}>{editCat?"Editar":"Nova"} Categoria</div>
            <div style={{display:"flex",flexDirection:"column",gap:16}}>
              <div><label className="lbl">Nome</label>
                <input className="fi" value={newCat.label} onChange={x=>setNewCat({...newCat,label:x.target.value})} placeholder="Ex: Fornecedores..."/>
              </div>
              <div>
                <label className="lbl">Cor</label>
                <div style={{display:"flex",flexWrap:"wrap",gap:7,marginTop:6}}>
                  {PALETTE.map(color=>(
                    <div key={color} style={{width:26,height:26,borderRadius:"50%",background:color,cursor:"pointer",border:newCat.bg===color?"3px solid #2C1A0E":"2px solid transparent",transform:newCat.bg===color?"scale(1.12)":"none",transition:"all .15s"}}
                      onClick={()=>setNewCat({...newCat,bg:color})}/>
                  ))}
                </div>
                {newCat.label&&(
                  <div style={{display:"flex",alignItems:"center",gap:9,marginTop:12,padding:"9px 13px",background:hl(newCat.bg),borderRadius:8}}>
                    <div style={{width:11,height:11,borderRadius:"50%",background:newCat.bg,flexShrink:0}}/>
                    <span style={{fontSize:13,color:newCat.bg,fontWeight:500}}>{newCat.label}</span>
                  </div>
                )}
              </div>
            </div>
            <div style={{display:"flex",gap:10,marginTop:20}}>
              <button className="bp" style={{flex:1}} onClick={saveCat}>Salvar</button>
              <button className="bo" onClick={()=>{setShowCat(false);setEditCat(null);}}>Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {/* Mobile nav */}
      <div className="mob-nav">
        {[["mensal","📅","Mensal"],["semanal","📆","Semanal"],["lista","📋","Lista"],["metas","🎯","Metas"],["clientes","👥","Clientes"]].map(([v,ic,l])=>(
          <button key={v} className={`mnb${view===v?" active":""}`} onClick={()=>setView(v)}>
            <span style={{fontSize:18}}>{ic}</span><span>{l}</span>
          </button>
        ))}
        <button className="mnb" onClick={()=>openNew()} style={{color:BRAND}}>
          <span style={{fontSize:22,lineHeight:1}}>＋</span>
          <span style={{color:BRAND}}>Novo</span>
        </button>
      </div>

      {showCliModal&&(
        <div className="overlay" onClick={()=>setShowCliModal(false)}>
          <div className="modal" onClick={x=>x.stopPropagation()} style={{maxWidth:420}}>
            <div style={{fontSize:18,fontWeight:500,marginBottom:20}}>{editCli?"Editar":"Novo"} Cliente</div>
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div><label className="lbl">Nome *</label><input className="fi" value={newCli.name} onChange={x=>setNewCli({...newCli,name:x.target.value})} placeholder="Nome completo"/></div>
              <div><label className="lbl">WhatsApp</label><input className="fi" value={newCli.phone} onChange={x=>setNewCli({...newCli,phone:x.target.value})} placeholder="5511999990001"/></div>
              <div><label className="lbl">Email</label><input className="fi" value={newCli.email} onChange={x=>setNewCli({...newCli,email:x.target.value})} placeholder="email@cliente.com"/></div>
              <div><label className="lbl">Notas</label><textarea className="fi" value={newCli.notes} onChange={x=>setNewCli({...newCli,notes:x.target.value})} placeholder="Observações..."/></div>
            </div>
            <div style={{display:"flex",gap:10,marginTop:20}}>
              <button className="btn-primary" style={{flex:1}} onClick={saveCli}>Salvar</button>
              <button className="btn-outline" onClick={()=>{setShowCliModal(false);setEditCli(null);}}>Cancelar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
